CREATE TABLE control_subcategories
(
	id serial,
	control_category_id integer DEFAULT NULL,
	name character varying (63) NOT NULL DEFAULT '',
	description text DEFAULT NULL,
	CONSTRAINT pk_control_subcategories PRIMARY KEY (id)
	, CONSTRAINT fk_control_subcategories_to_control_category FOREIGN KEY (control_category_id) REFERENCES control_categories (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_control_subcategories_control_category ON control_subcategories (control_category_id);
CREATE INDEX i_control_subcategories_name ON control_subcategories (name);
